INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('diplomatic-36ccc47a-moex-00590', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-110-7f4830a9', 'sub-diplomatic-36ccc47a-03', NULL, 'single_choice', '第一次世界大戰結束，全世界殖民地解放運動積極地在1920年代展開，中國也掀起「廢除不平等 條約」的浪潮。請問下列何者錯誤？', '["民國13年（1924年），孫中山在廣州發表《第一次全國代表大會宣言》，號召廢除不平等條約", "民國14年（1925年）5月，上海爆發勞資衝突，日本廠主槍殺華工，引起學生示威遊行。5月 3日，上海租界英國警察以暴力干涉，槍殺群眾，是為「五三慘案」，要求廢除不平等條約聲浪 越高", "民國14年（1925年），外商與中國勞工糾紛愈烈，廣州革命政府動員「省（廣州）港（香港） 罷工」持續16個月，導致香港經濟蕭條，英商大受打擊", "民國16年（1927年）1月，國民革命軍北伐，攻下兩湖、江西之後，國民政府收回漢口、九江 英租界，使國內反帝國主義運動達於高潮"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:28+00:00", "source_pdf_sha1": "b45ea0898757", "answer_pdf_sha1": "201d41272164", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL),
  ('diplomatic-36ccc47a-moex-00591', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-110-7f4830a9', 'sub-diplomatic-36ccc47a-03', NULL, 'single_choice', '美國在1940年代曾經積極調停中國國民黨和中國共產黨的衝突，下列敘述何者正確？', '["珍珠港事變後，美國派遣史迪威（JosephW.Stilwell）為特使，來華調停國共衝突", "二次大戰結束後，美國又派馬歇爾（GeorgeC.Marshall）為特使，來華調停。因此而有馬歇爾、 蔣中正和毛澤東的重慶會談", "由於國、共都不遵守停戰協定，美國總統羅斯福（FranklinD.Roosevelt）決定對華實施軍火禁 運，造成了內戰局面的改變", "民國38年（1949年）8月，美國國務院發表《中國白皮書》（ChinaWhitePaper），將中國局勢 的惡化，歸咎於中華民國政府"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:28+00:00", "source_pdf_sha1": "b45ea0898757", "answer_pdf_sha1": "201d41272164", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL),
  ('diplomatic-36ccc47a-moex-00592', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-110-7f4830a9', 'sub-diplomatic-36ccc47a-03', NULL, 'single_choice', '第二次世界大戰後，日本簽署了那一項條約，放棄對臺灣和澎湖群島的所有權利和主張？', '["美日共同合作與安全條約（TreatyofMutualCooperationandSecuritybetweentheUnitedStatesand Japan）", "舊金山和約（TreatyofPeacewithJapan）", "波茲坦宣言（PotsdamDeclaration）", "中日和約（TreatyofPeacebetweentheRepublicofChinaandJapan）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:28+00:00", "source_pdf_sha1": "b45ea0898757", "answer_pdf_sha1": "201d41272164", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL),
  ('diplomatic-36ccc47a-moex-00593', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-110-7f4830a9', 'sub-diplomatic-36ccc47a-03', NULL, 'single_choice', '關於1871年德國統一的過程，下列敘述何者錯誤？', '["普魯士領導的關稅同盟促成統一大業", "1864年普魯士排除奧國介入丹麥南方斯勒斯維格及霍恩斯坦兩公國主權之爭，掀起普丹戰爭", "普奧戰爭後普魯士採對奧國寬大政策減少了奧國憤恨和阻撓", "拿破崙三世逼迫普魯士不得干涉西班牙王位繼承，導致普法關係惡化最終引發戰爭"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:28+00:00", "source_pdf_sha1": "b45ea0898757", "answer_pdf_sha1": "201d41272164", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL),
  ('diplomatic-36ccc47a-moex-00594', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-110-7f4830a9', 'sub-diplomatic-36ccc47a-03', NULL, 'single_choice', '20世紀初的中國東北，曾是遠東的火藥庫之一，下列敘述何者錯誤？', '["日本在遼陽設立「關東都督府」，作為政治、軍事統治機關", "光緒33年（1907年），日、俄秘密成立協約，劃分南、北「滿洲」，南滿及朝鮮為日本勢力範 圍，北滿及外蒙古為俄國勢力範圍", "民國4年（1915年），日本向袁世凱提出《二十一條》，要求東北、內蒙特權", "袁世凱死後，日本即積極扶植東北軍閥段祺瑞，幕後控制東北"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:28+00:00", "source_pdf_sha1": "b45ea0898757", "answer_pdf_sha1": "201d41272164", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL),
  ('diplomatic-36ccc47a-moex-00595', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-110-7f4830a9', 'sub-diplomatic-36ccc47a-03', NULL, 'single_choice', '面對西方列強的威脅，清廷曾試圖推動重大政治改革以達到富國強兵之目的。下列敘述何者錯 誤？', '["自強運動主要訴求為富國強兵", "中國在英法聯軍中戰敗證明自強運動的失敗", "甲午戰爭的戰敗促使光緒皇帝推動變法", "戊戌變法的內容包含建立海軍學院、設立農、商速成學堂"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:28+00:00", "source_pdf_sha1": "b45ea0898757", "answer_pdf_sha1": "201d41272164", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL),
  ('diplomatic-36ccc47a-moex-00596', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-110-7f4830a9', 'sub-diplomatic-36ccc47a-03', NULL, 'single_choice', '1921年11月華盛頓會議召開，由美、英兩國主導，召開該會議的主要目的為何？', '["1919年《凡爾賽和約》未獲美國國會批准，美國希望解決日本在山東的特權問題", "因為蘇聯革命成功，英國欲藉此會議強化與日本的同盟關係，以便繼續聯日抗俄", "為了對抗新興的蘇聯，英美鼓勵日本建設海軍，增加日本的艦隊數量", "會中各國簽訂《九國公約》，保證中國領土主權完整，為日本在華特權地位提供了護身符"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:28+00:00", "source_pdf_sha1": "b45ea0898757", "answer_pdf_sha1": "201d41272164", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL),
  ('diplomatic-36ccc47a-moex-00597', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-110-7f4830a9', 'sub-diplomatic-36ccc47a-03', NULL, 'single_choice', '清朝簽訂的對外條約當中，那一個丟失的領土最多？', '["尼布楚條約", "璦琿條約", "北京條約", "南京條約"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:28+00:00", "source_pdf_sha1": "b45ea0898757", "answer_pdf_sha1": "201d41272164", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL),
  ('diplomatic-36ccc47a-moex-00598', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-110-7f4830a9', 'sub-diplomatic-36ccc47a-03', NULL, 'single_choice', '關於1899年美國的「門戶開放」（OpenDoor）政策，下列敘述何者正確？', '["英國希望中國遭到瓜分，因此不支持美國的門戶開放政策", "美國主張門戶開放政策，反映其擴張主義的意圖", "美國國務卿門羅（JamesMonroe）在光緒25年（1898年）通牒各國，要求確保各國在華平等的 商業機會", "美國曾多次動用武力，在中國捍衛「門戶開放」政策"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:28+00:00", "source_pdf_sha1": "b45ea0898757", "answer_pdf_sha1": "201d41272164", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL),
  ('diplomatic-36ccc47a-moex-00599', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-110-c655adf3', 'sub-diplomatic-36ccc47a-04', NULL, 'single_choice', '有關民主原則，下列敘述何者錯誤？', '["我國憲政體制係採直接民主制", "我國之主權屬於全體國民", "人民行使國家主權的方式，多係透過投票的方式為之", "原則上以多數決定之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:28+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL)
